// pitch % 12 -> letter (lowercase natural, UPPERCASE sharp) — matches player.js
const SEMI = ['c', 'C', 'd', 'D', 'e', 'f', 'F', 'g', 'G', 'a', 'A', 'b'];
const pitchToLetter = (p) => SEMI[((p % 12) + 12) % 12];
const pitchToOct = (p) => Math.floor(p / 12) - 1;

