const files = fs.readdirSync(SRC).filter((f) => f.endsWith('.csv')).sort();
const seen = new Set();
const songs = [];
let idx = 0;

// group byte-identical files; for each unique piece prefer the file that HAS metadata
// (so a newly-added duplicate copy can't knock a piece out of the catalog)
const byMd5 = {};
for (const f of files) {
  const m = crypto.createHash('md5').update(fs.readFileSync(path.join(SRC, f))).digest('hex');
  (byMd5[m] = byMd5[m] || []).push(f);
}
const reps = Object.keys(byMd5).map((m) => byMd5[m].find((x) => META[x]) || byMd5[m][0]).sort();

// A held note whose MIDI re-articulates on every 16th shows up as a long run of the same
// letter ("gggggggg" = machine-gun). Collapse runs of >=8 identical note-chars to one attack
// held over dashes ("g-------"). Threshold 8 only trips true artifacts; spaced repeats
// ("g---g---g") have dashes between them and are left untouched.
function collapseHeld(notation, thresh) {
  thresh = thresh || 8;
  const NOTE = 'cCdDefFgGaAb';
  return notation.split('\n').map(function (line) {
    const m = line.match(/^((?:RH|LH|R|L)?\s*-?\d+\|)(.*)$/);
    if (!m) return line;
    const body = m[2].split('');
    let i = 0;
    while (i < body.length) {
      const ch = body[i];
      if (NOTE.indexOf(ch) >= 0) {
        let j = i + 1;
        while (j < body.length && body[j] === ch) j++;
        if (j - i >= thresh) { for (let k = i + 1; k < j; k++) body[k] = '-'; }
        i = j;
      } else i++;
    }
    return m[1] + body.join('');
  }).join('\n');
}

for (const f of reps) {
  const meta = META[f];
  if (!meta) { console.log('  ⚠ no metadata:', f); continue; }
  const buf = fs.readFileSync(path.join(SRC, f));
  const parsed = parseCSV(buf.toString('utf8'));
  const conv = convert(parsed);
  conv.notation = collapseHeld(conv.notation);          // fix held-note artifacts (e.g. a pedal bass re-struck every 16th → "ggggg")
  const cover = coverFor(meta);
  const coverFile = COVER_MAP[meta.id] || meta.id;                    // mapped art, else same-name file
  if (fs.existsSync(ROOT + '/assets/covers/' + coverFile + '.webp')) cover.image = 'assets/covers/' + coverFile + '.webp';  // real art when present, else gradient
  songs.push({ meta, conv, cover, file: f });
  idx++;
}

